    await pushSchema(repoDb);
    await setupLogContentFts(repoDb);
    process.stderr.write(`[gossamer] schema ready: ${repo.dbPath}\n`);
  } catch (err) {
    process.stderr.write(`[gossamer] schema push failed for ${repo.name} — ${err}\n`);
  }
}

